16	    package_graph::{self, PackageGraph, PackageName},
17	};
18	use turborepo_scm::SCM;
19	use turborepo_types::FilterMode;
20	use wax::Program;
21	
22	use crate::{
23	    ScopeOpts,
24	    change_detector::{GitChangeDetector, ScopeChangeDetector},
25	    simple_glob::{Match, SimpleGlob},
26	    target_selector::{GitRange, InvalidSelectorError, TargetSelector},
27	};
28	
29	/// Package inference for directory-based filtering.
30	pub struct PackageInference {
31	    package_name: Option<String>,
32	    directory_root: AnchoredSystemPathBuf,
33	}
34	
35	impl PackageInference {
36	    // calculate, based on the directory that global turbo was invoked in,
37	    // the pieces of a filter spec that we will infer. If turbo was invoked
38	    // somewhere between the root and packages, scope turbo invocations to the
39	    // packages below where turbo was invoked. If turbo was invoked at or within
40	    // a particular package, scope the turbo invocation to just that package.
41	    pub fn calculate(
42	        turbo_root: &AbsoluteSystemPath,
43	        pkg_inference_path: &AnchoredSystemPathBuf,
44	        pkg_graph: &PackageGraph,
45	    ) -> Self {
46	        debug!(
47	            "Using {} as a basis for selecting packages",
48	            pkg_inference_path
49	        );
50	        let full_inference_path = turbo_root.resolve(pkg_inference_path);
51	
52	        // Track the best matching package (the one whose path is the longest prefix
53	        // of the inference path, i.e., the most specific package containing our
54	        // current directory)
55	        let mut best_match: Option<(String, AnchoredSystemPathBuf)> = None;
56	        let mut found_package_below = false;
57	
58	        for (workspace_name, workspace_entry) in pkg_graph.packages() {
59	            let pkg_path = turbo_root.resolve(workspace_entry.package_path());
60	
61	            // Check if the inference path is inside this package (pkg_path is a prefix of
62	            // full_inference_path)
63	            let inferred_path_is_below = pkg_path.contains(&full_inference_path);
64	
65	            // We skip over the root package as the inferred path will always be below it
66	            if inferred_path_is_below && (&pkg_path as &AbsoluteSystemPath) != turbo_root {
67	                // This package contains the inference path. Track it if it's a better
68	                // (longer/more specific) match than what we've found so far.
69	                let pkg_path_len = workspace_entry.package_path().as_str().len();
